export const getSchoolSido = (slug: string) => SCHOOLS.find((s) => s.slug === slug);

// 한 시/도의 전체 학교를 가나다순 평탄화 (전체보기 탭용)
export const allSchoolsOf = (sidoSlug: string) =>
  (getSchoolSido(sidoSlug)?.sigungu ?? [])
    .flatMap((sg) => sg.schools.map((sc) => ({ ...sc, sigungu: sg.name, sigunguSlug: sg.slug })))
    .sort((a, b) => a.name.localeCompare(b.name, "ko"));
